import React, { Suspense, lazy } from 'react';
import { Routes, Route, Navigate } from 'react-router-dom';
import { ThemeProvider, createTheme } from '@mui/material/styles';
import CssBaseline from '@mui/material/CssBaseline';

import { AuthProvider, useAuth } from './contexts/AuthContext';
import ProtectedRoute from './components/ProtectedRoute';
import AppLayout from './components/AppLayout';
import Loader from './components/Loader';

// ================= LAZY PAGES =================
const Login = lazy(() => import('./pages/Login'));
const ChangePassword = lazy(() => import('./pages/ChangePassword'));
const Profile = lazy(() => import('./pages/Profile'));

// Employee
const EmployeeDashboard = lazy(() => import('./pages/employee/EmployeeDashboard'));
const PunchHistory = lazy(() => import('./pages/employee/PunchHistory'));
const PunchCorrections = lazy(() => import('./pages/employee/PunchCorrections'));
const CreateAllowance = lazy(() => import('./pages/employee/CreateAllowance'));
const AllowanceHistory = lazy(() => import('./pages/employee/AllowanceHistory'));
const PendingApprovals = lazy(() => import('./pages/admin/PendingApprovals'));
const DailySummary = lazy(() => import('./pages/employee/DailySummary'));

// Admin
const AdminDashboard = lazy(() => import('./pages/admin/AdminDashboard'));
const UserManagement = lazy(() => import('./pages/admin/UserManagement'));
const CreateUser = lazy(() => import('./pages/admin/CreateUser'));
const PunchDetails = lazy(() => import('./pages/admin/PunchDetails'));
const EmployeeTracking = lazy(() => import('./pages/admin/EmployeeTracking'));
const CRMVisits = lazy(() => import('./pages/admin/CRMVisits'));
const ProfileApproval = lazy(() => import('./pages/admin/ProfileApproval'));
const Unauthorized = lazy(() => import('./components/Unauthorized'));

// ================= THEME =================
const theme = createTheme({
    palette: {
        primary: { main: '#1976d2' },
        secondary: { main: '#dc004e' },
    },
});


// ================= ROOT REDIRECTOR =================
const RootRedirect = () => {
    const { user, loading } = useAuth();

    if (loading) return <Loader />;

    if (!user) return <Navigate to="/login" replace />;

    if (user.force_password_change) {
        return <Navigate to="/change-password" replace />;
    }

    if (user.role_name === 'ADMIN' || user.role_name === 'SUPER_ADMIN') {
        return <Navigate to="/admin/dashboard" replace />;
    }

    if (user.role_name === 'EMPLOYEE') {
        return <Navigate to="/employee/dashboard" replace />;
    }

    return <Navigate to="/login" replace />;
};


// ================= ROUTES =================
const AppRoutes = () => {
    return (
        <Suspense fallback={<Loader />}>
            <Routes>

                {/* PUBLIC */}
                <Route path="/login" element={<Login />} />

                {/* ROOT CONTROL */}
                <Route path="/" element={<RootRedirect />} />

                {/* COMMON */}
                <Route
                    path="/change-password"
                    element={
                        <ProtectedRoute>
                            <ChangePassword />
                        </ProtectedRoute>
                    }
                />

                <Route
                    path="/profile"
                    element={
                        <ProtectedRoute>
                            <AppLayout>
                                <Profile />
                            </AppLayout>
                        </ProtectedRoute>
                    }
                />

                {/* ================= EMPLOYEE ================= */}
                <Route
                    path="/employee/dashboard"
                    element={
                        <ProtectedRoute roles={['EMPLOYEE']}>
                            <AppLayout>
                                <EmployeeDashboard />
                            </AppLayout>
                        </ProtectedRoute>
                    }
                />
                <Route
                    path="/employee/punch-corrections"
                    element={
                        <ProtectedRoute requiredRoles={['EMPLOYEE']}>
                            <AppLayout><PunchCorrections /></AppLayout>
                        </ProtectedRoute>
                    }
                />

                <Route
                    path="/employee/create-allowance"
                    element={
                        <ProtectedRoute requiredRoles={['EMPLOYEE']}>
                            <AppLayout><CreateAllowance /></AppLayout>
                        </ProtectedRoute>
                    }
                />

                <Route
                    path="/employee/allowance-history"
                    element={
                        <ProtectedRoute requiredRoles={['EMPLOYEE']}>
                            <AppLayout><AllowanceHistory /></AppLayout>
                        </ProtectedRoute>
                    }
                />
                <Route
                    path="/employee/daily-summary"
                    element={
                        <ProtectedRoute requiredRoles={['EMPLOYEE']}>
                            <AppLayout>
                                <DailySummary />
                            </AppLayout>
                        </ProtectedRoute>
                    }
                />
                <Route
                    path="/employee/punch-history"
                    element={
                        <ProtectedRoute roles={['EMPLOYEE']}>
                            <AppLayout>
                                <PunchHistory />
                            </AppLayout>
                        </ProtectedRoute>
                    }
                />

                {/* ================= ADMIN ================= */}
                <Route
                    path="/admin/dashboard"
                    element={
                        <ProtectedRoute roles={['ADMIN', 'SUPER_ADMIN']}>
                            <AppLayout>
                                <AdminDashboard />
                            </AppLayout>
                        </ProtectedRoute>
                    }
                />

                <Route
                    path="/admin/users"
                    element={
                        <ProtectedRoute roles={['ADMIN', 'SUPER_ADMIN']}>
                            <AppLayout>
                                <UserManagement />
                            </AppLayout>
                        </ProtectedRoute>
                    }
                />

                <Route
                    path="/admin/create-user"
                    element={
                        <ProtectedRoute roles={['ADMIN', 'SUPER_ADMIN']}>
                            <AppLayout>
                                <CreateUser />
                            </AppLayout>
                        </ProtectedRoute>
                    }
                />
                <Route
                    path="/admin/pending-approvals"
                    element={
                        <ProtectedRoute requiredRoles={['ADMIN', 'SUPER_ADMIN']}>
                            <AppLayout><PendingApprovals /></AppLayout>
                        </ProtectedRoute>
                    }
                />

                <Route
                    path="/admin/punch-details"
                    element={
                        <ProtectedRoute requiredRoles={['ADMIN', 'SUPER_ADMIN']}>
                            <AppLayout><PunchDetails /></AppLayout>
                        </ProtectedRoute>
                    }
                />

                <Route
                    path="/admin/employee-tracking"
                    element={
                        <ProtectedRoute requiredRoles={['ADMIN', 'SUPER_ADMIN']}>
                            <AppLayout><EmployeeTracking /></AppLayout>
                        </ProtectedRoute>
                    }
                />

                <Route
                    path="/admin/crm-visits"
                    element={
                        <ProtectedRoute requiredRoles={['ADMIN', 'SUPER_ADMIN']}>
                            <AppLayout><CRMVisits /></AppLayout>
                        </ProtectedRoute>
                    }
                />

                <Route
                    path="/admin/punch-corrections"
                    element={
                        <ProtectedRoute requiredRoles={['ADMIN', 'SUPER_ADMIN']}>
                            <AppLayout><PunchCorrections /></AppLayout>
                        </ProtectedRoute>
                    }
                />

                <Route
                    path="/admin/profile-approval"
                    element={
                        <ProtectedRoute requiredRoles={['ADMIN', 'SUPER_ADMIN']}>
                            <AppLayout><ProfileApproval /></AppLayout>
                        </ProtectedRoute>
                    }
                />

                {/* FALLBACK */}
                <Route path="/unauthorized" element={<Unauthorized />} />
                <Route path="*" element={<Navigate to="/" replace />} />

            </Routes>
        </Suspense>
    );
};


// ================= MAIN APP =================
const App = () => {
    return (
        <ThemeProvider theme={theme}>
            <CssBaseline />

            <AuthProvider>
                <AppRoutes />
            </AuthProvider>

        </ThemeProvider>
    );
};

export default App;